    for delimiter in ['|', ':', ';', ',']:
        if delimiter in packet:
            parts = packet.split(delimiter)
            if len(parts) >= 2:
                # Last part is likely checksum
                data_parts = parts[:-1]
                old_checksum = parts[-1]
                data = delimiter.join(data_parts)

