    try:
        packet = decode_fluxon_frame(frame)
    except ValueError:
        return -1

    parts = packet.split("::")

    # Packet format: FXN::<version>::<channel>::<payload>::<checksum>
    if len(parts) != 5:
        return -1

    if parts[0] != "FXN":
        return -1

    try:
        version = int(parts[1])
        checksum = int(parts[4])
    except ValueError:
        return -1

    if version not in _VALID_VERSIONS:
        return -1

    channel = parts[2]
    if channel not in _VALID_CHANNELS:
        return -1

    payload = parts[3]

    # Validate checksum
    try:
        expected_checksum = compute_fluxon_checksum(payload, version)
    except ValueError:
        return -1

    if checksum != expected_checksum:
        return -1

    # Count tokens in payload
    tokens = split_fluxon_payload(payload)

    # Validate all tokens
    for token in tokens:
        if not _TOKEN_PATTERN.match(token):
            return -1

    return len(tokens)
